from django.contrib.auth.models import AbstractUser from django.db import models
class Role(models.Model): name = models.CharField(max_length=100, unique=True) description = models.TextField(blank=True) is_active = models.BooleanField(default=True) created_at = models.DateTimeField(auto_now_add=True) updated_at = models.DateTimeField(auto_now=True)
def __str__(self): return self.name
class User(AbstractUser): email = models.EmailField(unique=True) roles = models.ManyToManyField(Role, blank=True, related_name='users')
REQUIRED_FIELDS = ['email']
def __str__(self): return self.username

