import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';
import { AuthProvider } from './context/AuthContext';
import Layout from './components/Layout';
import Home from './pages/Home';
import Events from './pages/Events';
import Publications from './pages/Publications';
import Dashboard from './pages/Dashboard';

const theme = createTheme();

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <Router>
          <Layout>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/events" element={<Events />} />
              <Route path="/publications" element={<Publications />} />
              <Route path="/dashboard" element={<Dashboard />} />
              {/* Add more routes as needed */}
            </Routes>
          </Layout>
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
}

export default App;

import React from 'react';
import { AppBar, Toolbar, Typography, Button, Container, Box } from '@mui/material';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Layout = ({ children }) => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" component={Link} to="/" sx={{ flexGrow: 1, textDecoration: 'none', color: 'inherit' }}>
            MAOMS
          </Typography>
          <Button color="inherit" component={Link} to="/">Home</Button>
          <Button color="inherit" component={Link} to="/events">Events</Button>
          <Button color="inherit" component={Link} to="/publications">Publications</Button>
          <Button color="inherit" component={Link} to="/resources">Resources</Button>
          <Button color="inherit" component={Link} to="/contact">Contact</Button>
          {user ? (
            <>
              <Button color="inherit" component={Link} to="/dashboard">Dashboard</Button>
              <Button color="inherit" onClick={handleLogout}>Logout</Button>
            </>
          ) : (
            <Button color="inherit" component={Link} to="/login">Login</Button>
          )}
        </Toolbar>
      </AppBar>
      <Container component="main" sx={{ flexGrow: 1, py: 3 }}>
        {children}
      </Container>
      <Box component="footer" sx={{ py: 3, px: 2, mt: 'auto', backgroundColor: 'grey.200' }}>
        <Container maxWidth="sm">
          <Typography variant="body1" align="center">
            © 2026 MAOMS. All rights reserved.
          </Typography>
        </Container>
      </Box>
    </Box>
  );
};

export default Layout;

import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../services/api';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      // Verify token and get user info
      api.get('auth/user/')
        .then(response => {
          setUser(response.data);
        })
        .catch(() => {
          localStorage.removeItem('token');
        })
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (username, password) => {
    const response = await api.post('auth/login/', { username, password });
    const { token, user } = response.data;
    localStorage.setItem('token', token);
    setUser(user);
    return user;
  };

  const logout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  const value = {
    user,
    login,
    logout,
    loading,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { useState, useEffect } from 'react';
import { Typography, Grid, Card, CardContent, Button, List, ListItem, ListItemText, Divider } from '@mui/material';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const Dashboard = () => {
  const { user } = useAuth();
  const [memberProfile, setMemberProfile] = useState(null);
  const [myEvents, setMyEvents] = useState([]);
  const [myPublications, setMyPublications] = useState([]);

  useEffect(() => {
    if (user) {
      // Fetch member profile
      api.get('members/profile/')
        .then(response => setMemberProfile(response.data))
        .catch(error => console.error('Error fetching profile:', error));

      // Fetch user's events
      api.get('events/my/')
        .then(response => setMyEvents(response.data))
        .catch(error => console.error('Error fetching events:', error));

      // Fetch user's publications
      api.get('publications/my/')
        .then(response => setMyPublications(response.data))
        .catch(error => console.error('Error fetching publications:', error));
    }
  }, [user]);

  if (!user) return <Typography>Please log in to access the dashboard.</Typography>;

  return (
    <div>
      <Typography variant="h4" gutterBottom>
        Dashboard
      </Typography>
      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Profile
              </Typography>
              {memberProfile ? (
                <div>
                  <Typography>Name: {memberProfile.first_name} {memberProfile.last_name}</Typography>
                  <Typography>Email: {memberProfile.email}</Typography>
                  <Typography>Membership: {memberProfile.membership_type}</Typography>
                  <Button component={Link} to="/profile/edit" variant="outlined" sx={{ mt: 2 }}>
                    Edit Profile
                  </Button>
                </div>
              ) : (
                <Typography>Loading profile...</Typography>
              )}
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                My Events
              </Typography>
              <List>
                {myEvents.slice(0, 5).map(event => (
                  <ListItem key={event.id}>
                    <ListItemText primary={event.title} secondary={new Date(event.start_date).toLocaleDateString()} />
                  </ListItem>
                ))}
              </List>
              <Button component={Link} to="/events" variant="outlined">
                View All Events
              </Button>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                My Publications
              </Typography>
              <List>
                {myPublications.slice(0, 5).map(pub => (
                  <ListItem key={pub.id}>
                    <ListItemText primary={pub.title} secondary={pub.status} />
                  </ListItem>
                ))}
              </List>
              <Button component={Link} to="/publications" variant="outlined">
                View All Publications
              </Button>
            </CardContent>
          </Card>
        </Grid>
        {user.roles && user.roles.some(role => role.name === 'admin' || role.name === 'reviewer') && (
          <Grid item xs={12}>
            <Card>
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  Admin Actions
                </Typography>
                <Button component={Link} to="/admin/events" variant="contained" sx={{ mr: 2 }}>
                  Manage Events
                </Button>
                <Button component={Link} to="/admin/publications" variant="contained" sx={{ mr: 2 }}>
                  Manage Publications
                </Button>
                <Button component={Link} to="/admin/members" variant="contained">
                  Manage Members
                </Button>
              </CardContent>
            </Card>
          </Grid>
        )}
      </Grid>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Typography, Grid, Card, CardContent, CardMedia, Button, Chip } from '@mui/material';
import { Link } from 'react-router-dom';
import api from '../services/api';

const Events = () => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('events/')
      .then(response => {
        setEvents(response.data);
      })
      .catch(error => {
        console.error('Error fetching events:', error);
      })
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <Typography>Loading...</Typography>;

  return (
    <div>
      <Typography variant="h4" gutterBottom>
        Events
      </Typography>
      <Grid container spacing={3}>
        {events.map(event => (
          <Grid item xs={12} md={6} lg={4} key={event.id}>
            <Card>
              {event.banner && (
                <CardMedia
                  component="img"
                  height="140"
                  image={event.banner}
                  alt={event.title}
                />
              )}
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  {event.title}
                </Typography>
                <Typography variant="body2" color="textSecondary" gutterBottom>
                  {event.description.substring(0, 100)}...
                </Typography>
                <Typography variant="body2">
                  {new Date(event.start_date).toLocaleDateString()} - {new Date(event.end_date).toLocaleDateString()}
                </Typography>
                <Chip label={event.event_type} size="small" sx={{ mt: 1 }} />
                <Button component={Link} to={`/events/${event.id}`} variant="outlined" sx={{ mt: 2 }}>
                  View Details
                </Button>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </div>
  );
};

export default Events;

